import asyncio
import websockets
import json
import uuid
from typing import Dict, List, Set
from dataclasses import dataclass
from collections import defaultdict

@dataclass
class Item:
    id: str
    name: str
    type: str
    value: int

@dataclass
class Player:
    id: str
    name: str
    inventory: Dict[str, int]
    websocket: websockets.WebSocketServerProtocol

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.active_connections: Set[websockets.WebSocketServerProtocol] = set()
        self.trade_requests: Dict[str, Dict] = {}
        self.trade_lock = asyncio.Lock()

    async def register_player(self, websocket, player_name):
        player_id = str(uuid.uuid4())
        player = Player(player_id, player_name, {}, websocket)
        self.players[player_id] = player
        self.active_connections.add(websocket)
        await self.send_message(websocket, {
            "type": "player_registered",
            "player_id": player_id
        })
        return player_id

    async def unregister_player(self, websocket):
        self.active_connections.discard(websocket)
        for player_id, player in self.players.items():
            if player.websocket == websocket:
                del self.players[player_id]
                break

    async def send_message(self, websocket, message):
        try:
            await websocket.send(json.dumps(message))
        except websockets.exceptions.ConnectionClosed:
            await self.unregister_player(websocket)

    async def broadcast_message(self, message):
        message_str = json.dumps(message)
        disconnected = set()
        for websocket in self.active_connections:
            try:
                await websocket.send(message_str)
            except websockets.exceptions.ConnectionClosed:
                disconnected.add(websocket)
        for websocket in disconnected:
            await self.unregister_player(websocket)

    async def handle_message(self, websocket, message):
        try:
            data = json.loads(message)
            message_type = data.get("type")
            
            if message_type == "register":
                player_id = await self.register_player(websocket, data.get("name"))
                await self.send_message(websocket, {
                    "type": "registration_success",
                    "player_id": player_id
                })
            
            elif message_type == "get_inventory":
                player_id = data.get("player_id")
                if player_id in self.players:
                    await self.send_message(websocket, {
                        "type": "inventory_response",
                        "inventory": self.players[player_id].inventory
                    })
            
            elif message_type == "trade_request":
                from_player_id = data.get("from_player_id")
                to_player_id = data.get("to_player_id")
                item_id = data.get("item_id")
                quantity = data.get("quantity", 1)
                
                if (from_player_id in self.players and 
                    to_player_id in self.players and
                    item_id in self.players[from_player_id].inventory and
                    self.players[from_player_id].inventory[item_id] >= quantity):
                    
                    trade_id = str(uuid.uuid4())
                    self.trade_requests[trade_id] = {
                        "from_player": from_player_id,
                        "to_player": to_player_id,
                        "item_id": item_id,
                        "quantity": quantity,
                        "status": "pending"
                    }
                    
                    await self.send_message(self.players[to_player_id].websocket, {
                        "type": "trade_proposal",
                        "trade_id": trade_id,
                        "from_player": from_player_id,
                        "item": item_id,
                        "quantity": quantity
                    })
            
            elif message_type == "accept_trade":
                trade_id = data.get("trade_id")
                if trade_id in self.trade_requests:
                    trade = self.trade_requests[trade_id]
                    if trade["status"] == "pending":
                        async with self.trade_lock:
                            await self.execute_trade(trade)
                            self.trade_requests.pop(trade_id, None)
            
            elif message_type == "reject_trade":
                trade_id = data.get("trade_id")
                if trade_id in self.trade_requests:
                    self.trade_requests.pop(trade_id, None)
            
            elif message_type == "item_purchase":
                player_id = data.get("player_id")
                item_id = data.get("item_id")
                quantity = data.get("quantity", 1)
                
                if player_id in self.players and item_id in self.items:
                    item = self.items[item_id]
                    # Simplified economy logic - in real game you'd check currency
                    if player_id in self.players:
                        if item_id not in self.players[player_id].inventory:
                            self.players[player_id].inventory[item_id] = 0
                        self.players[player_id].inventory[item_id] += quantity
                        await self.broadcast_message({
                            "type": "item_acquired",
                            "player_id": player_id,
                            "item_id": item_id,
                            "quantity": quantity
                        })
        
        except Exception as e:
            print(f"Error handling message: {e}")

    async def execute_trade(self, trade):
        from_player_id = trade["from_player"]
        to_player_id = trade["to_player"]
        item_id = trade["item_id"]
        quantity = trade["quantity"]
        
        from_player = self.players[from_player_id]
        to_player = self.players[to_player_id]
        
        # Update inventory quantities
        from_player.inventory[item_id] -= quantity
        if from_player.inventory[item_id] <= 0:
            del from_player.inventory[item_id]
        
        if item_id not in to_player.inventory:
            to_player.inventory[item_id] = 0
        to_player.inventory[item_id] += quantity
        
        # Send confirmation to both players
        await self.send_message(from_player.websocket, {
            "type": "trade_completed",
            "trade_id": trade["from_player"] + "_" + trade["to_player"],
            "item": item_id,
            "quantity": quantity,
            "result": "success"
        })
        
        await self.send_message(to_player.websocket, {
            "type": "trade_completed",
            "trade_id": trade["from_player"] + "_" + trade["to_player"],
            "item": item_id,
            "quantity": quantity,
            "result": "success"
        })
        
        # Broadcast inventory update
        await self.broadcast_message({
            "type": "inventory_update",
            "player_id": from_player_id,
            "inventory": from_player.inventory
        })
        
        await self.broadcast_message({
            "type": "inventory_update",
            "player_id": to_player_id,
            "inventory": to_player.inventory
        })

    async def start_server(self, host='localhost', port=8765):
        self.items["sword_001"] = Item("sword_001", "Iron Sword", "weapon", 100)
        self.items["potion_001"] = Item("potion_001", "Health Potion", "consumable", 50)
        self.items["shield_001"] = Item("shield_001", "Wooden Shield", "armor", 75)
        
        server = await websockets.serve(
            self.handle_connection,
            host,
            port
        )
        print(f"Server started on {host}:{port}")
        await server.wait_closed()

    async def handle_connection(self, websocket, path):
        async for message in websocket:
            await self.handle_message(websocket, message)

# Initialize and start the server
if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.start_server())